// Aggregate analytics data for AI analysis
const items = $input.all();

const analyticsData = items.map(item => ({
  topic: item.json.Post_Topic || '',
  style: item.json.Visual_Style || '',
  views: item.json.Views || 0,
  likes: item.json.Likes || 0,
  shares: item.json.Shares || 0,
  saves: item.json.Saves || 0,
  engagement: item.json.Engagement_Rate || 0
}));

// Extract custom topics
const customTopics = items
  .filter(i => i.json.Topic_Title)
  .map(i => ({
    title: i.json.Topic_Title,
    description: i.json.Description,
    keywords: i.json.Keywords
  }));

// Calculate top performers
const scored = analyticsData
  .filter(a => a.topic)
  .map(a => ({
    ...a,
    score: (a.saves * 3) + (a.shares * 2) + a.likes + (a.views * 0.01)
  }))
  .sort((a, b) => b.score - a.score);

const topTopics = [...new Set(scored.slice(0, 5).map(s => s.topic))];
const topStyles = [...new Set(scored.slice(0, 5).map(s => s.style))];

return [{
  json: {
    analytics_summary: JSON.stringify(scored.slice(0, 20)),
    custom_topics: JSON.stringify(customTopics),
    top_topics: topTopics,
    top_styles: topStyles,
    total_posts_analyzed: analyticsData.filter(a => a.topic).length,
    analysis_date: new Date().toISOString().split('T')[0]
  }
}];

