const aiResponse = $input.first().json;
let contentPlan;

try {
  const text = aiResponse.candidates[0].content.parts[0].text;
  contentPlan = JSON.parse(text);
} catch(e) {
  throw new Error('Failed to parse content plan from AI: ' + e.message);
}

if (!Array.isArray(contentPlan) || contentPlan.length < 1) {
  throw new Error('Content plan is empty or invalid');
}

// Calculate dates for the coming week
const today = new Date();
const monday = new Date(today);
monday.setDate(today.getDate() + (1 - today.getDay() + 7) % 7);
if (monday <= today) monday.setDate(monday.getDate() + 7);

const weekNum = Math.ceil((monday.getTime() - new Date(monday.getFullYear(), 0, 1).getTime()) / (7 * 24 * 60 * 60 * 1000));

const items = contentPlan.map((item, idx) => {
  const dayOffset = Math.floor(idx / 2);
  const date = new Date(monday);
  date.setDate(monday.getDate() + dayOffset);

  return {
    json: {
      Date: date.toISOString().split('T')[0],
      Day_Number: dayOffset + 1,
      Topic_UZ: item.topic_uz || '',
      Topic_EN: item.topic_en || '',
      Visual_Style: item.visual_style || 'hi-tech facade',
      Content_Type: item.content_type || 'Reel',
      Status: 'Pending',
      Week_Number: weekNum,
      Priority_Score: item.priority_score || 50,
      Slot: item.slot || (idx % 2 === 0 ? 'morning' : 'afternoon')
    }
  };
});

return items;

